import { useEffect, useMemo, type ReactNode } from 'react';
import { createTooltipManager, type TooltipManagerConfig } from '@o9ds/core';
import { TooltipContext } from './TooltipContext';

export interface TooltipProviderProps {
  config?: Partial<TooltipManagerConfig>;
  children: ReactNode;
}

export function TooltipProvider({
  config,
  children,
}: TooltipProviderProps): JSX.Element {
  const manager = useMemo(() => {
    const m = createTooltipManager();
    if (config) m.configure(config);
    return m;
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  useEffect(() => {
    if (config) manager.configure(config);
  }, [manager, config]);

  useEffect(() => {
    return () => manager.destroy();
  }, [manager]);

  return (
    <TooltipContext.Provider value={manager}>{children}</TooltipContext.Provider>
  );
}
